def _uk_kind_value(kind: IRNodeKind | str) -> str:
    if isinstance(kind, IRNodeKind):
        return kind.value
    return str(kind or "")


def _uk_eid_value(eid: Any) -> str | None:
    if eid is None:
        return None
    if isinstance(eid, IRNodeKind):
        return eid.value
    return str(eid)


def _make_address(
    container: str,
    section: Optional[str] = None,
    part: Optional[str] = None,
    chapter: Optional[str] = None,
    subsection: Optional[str] = None,
    item: Optional[str] = None,
    special: Optional[FacetKind] = None,
) -> LegalAddress:
    """Build a LegalAddress from the flat-field style used by the UK parser."""
    path: list[tuple[str, str]] = []
    if container == "schedule":
        if section is not None:
            path.append(("schedule", section))
        if part:
            path.append(("part", part))
        if chapter:
            path.append(("chapter", chapter))
        if subsection:
            path.append(("paragraph", subsection))
        if item:
            path.append(("paragraph", item))
    else:
        if part:
            path.append(("part", part))
        if chapter:
            path.append(("chapter", chapter))
        if section:
            path.append(("section", section))
        if subsection:
            path.append(("subsection", subsection))
        if item:
            path.append(("paragraph", item))
    return LegalAddress(path=tuple(path), special=special)


def _addr_container(addr: LegalAddress) -> str:
    """Return the top-level container kind of a LegalAddress."""
    return uk_addr_container(addr)


def _addr_field(addr: LegalAddress, kind: str) -> Optional[str]:
    """Return the label for the first path segment matching *kind*, or None."""
    for k, lbl in addr.path:
        if k == kind:
            return lbl
    return None


def _addr_leaf_label(addr: LegalAddress) -> Optional[str]:
    """Return the deepest meaningful label from a LegalAddress path."""
    for kind, lbl in reversed(addr.path):
        if lbl:
            return lbl
    return None


def _addr_leaf_kind(addr: LegalAddress) -> Optional[str]:
    """Return the deepest path kind from a LegalAddress, if any."""
    if not addr.path:
        return None
    return addr.path[-1][0]


def _schedule_target_levels(addr: LegalAddress) -> tuple[Optional[str], Optional[str], list[str]]:
    """Return typed schedule descendant labels as (paragraph, subparagraph, items)."""
    paragraph = None
    subparagraph = None
    items: list[str] = []
    for kind, lbl in addr.path:
        if not lbl:
            continue
        if kind == "paragraph":
            paragraph = lbl
        elif kind == "subparagraph":
            subparagraph = lbl
        elif kind in {"item", "point"}:
            items.append(lbl)
    return paragraph, subparagraph, items


def _looks_like_lettered_item_label(label: str) -> bool:
    return bool(re.fullmatch(r"[a-z]+", (label or "").strip(), re.I))


def _canonicalize_schedule_paragraph_eid_label(label: Optional[str]) -> str:
    """Canonicalize schedule paragraph labels for exact eId lookup.

    UK schedule paragraph ids can surface as lower-case aliases like ``9a`` or
    ``116a`` in affected-target text, while the parsed/oracle eId may retain an
    upper-case alpha suffix such as ``9A`` or ``116A``.

    We keep the normalization narrow: only the first alpha suffix immediately
    following leading digits is upper-cased, leaving any later nested item
    suffixes untouched (for example ``116a-a`` -> ``116A-a``).
    """

    cleaned = _clean_num(label or "")
    if not cleaned:
        return ""
    match = re.fullmatch(r"(\d+)([a-z])(?P<rest>.*)", cleaned)
    if match:
        return f"{match.group(1)}{match.group(2).upper()}{match.group('rest')}"
    return cleaned


def _canonicalize_eid_tail_label(label: Optional[str]) -> str:
    """Canonicalize descendant eId suffixes without Romanizing letter labels."""
    raw = str(label or "").strip().replace("\u00a0", " ")
    if not raw:
        return ""
    stripped = raw.strip("().").lower()
    if re.fullmatch(r"[a-z]+", stripped):
        return stripped
    return _clean_num(raw)


def _order_schedule_materialization_ops(ops: list[LegalOperation]) -> list[LegalOperation]:
    """Prioritize materializing structural ops before dependent text edits within a source."""
    structural_materialization_targets = {
        (
            str(getattr(op.source, "effective", "") or ""),
            str(getattr(op.source, "statute_id", "") or ""),
            tuple(op.target.path or ()),
        )
        for op in ops
        if _action_name(op.action) in {"insert", "replace"}
    }

    def _rank(op: LegalOperation) -> int:
        if op.target.special is FacetKind.HEADING and _action_name(op.action) in {"text_replace", "text_repeal"}:
            structural_key = (
                str(getattr(op.source, "effective", "") or ""),
                str(getattr(op.source, "statute_id", "") or ""),
                tuple(op.target.path or ()),
            )
            if structural_key in structural_materialization_targets:
                return 1
            return -1
        if _action_name(op.action) in {"insert", "replace", "repeal", "renumber"}:
            return 0
        if _action_name(op.action) in {"text_replace", "text_repeal"}:
            return 1
        return 2

    return [
        op
        for _idx, op in sorted(
            enumerate(ops),
            key=lambda item: (
                str(getattr(item[1].source, "effective", "") or ""),
                str(getattr(item[1].source, "statute_id", "") or ""),
                _rank(item[1]),
                item[0],
            ),
        )
    ]


def _looks_like_roman_subitem_label(label: str) -> bool:
    cleaned = (label or "").strip().lower()
    return bool(cleaned) and bool(re.fullmatch(r"[ivx]+", cleaned))


def _action_name(action: StructuralAction | str) -> str:
    """Return the canonical lower-case action string for enum or legacy string values."""
    if isinstance(action, StructuralAction):
        return action.value
    return str(action)


def _uk_definition_term_lexical_variants(term: str) -> tuple[str, ...]:
    """Return narrow UK definition-anchor lexical variants.

    This is target-resolution recovery, not fuzzy matching.  Keep the family
    deliberately small: UK sources can use the adjectival form "educational"
    where the enacted definition label uses the noun "education".
    """
    cleaned = " ".join(str(term or "").split())
    if not cleaned:
        return ()
    variants: list[str] = []
    words = cleaned.split(" ")
    for i, word in enumerate(words):
        lower = word.lower()
        if lower == "educational":
            variant_words = list(words)
            variant_words[i] = "education"
            variants.append(" ".join(variant_words))
        elif lower == "education":
            variant_words = list(words)
            variant_words[i] = "educational"
            variants.append(" ".join(variant_words))
    return tuple(dict.fromkeys(variant for variant in variants if variant != cleaned))


def _direct_structural_num(el: ET.Element) -> str:
    """Return the node's own structural number, not a descendant's number."""
    num_el = el.find(f"./{{{_LEG_NS}}}Pnumber")
    if num_el is None:
        num_el = el.find(f"./{{{_LEG_NS}}}Number")
    if num_el is None and _tag(el) == "Schedule":
        num_el = el.find(f".//{{{_LEG_NS}}}Number")
    if num_el is None:
        return ""
    return _text_content(num_el)


def _is_heading_only_ref(ref: str) -> bool:
    ref_clean = ref.strip().lower()
    if "cross-heading" in ref_clean or "cross heading" in ref_clean or "crossheading" in ref_clean:
        return False
    return ref_clean.endswith(" heading") or ref_clean.endswith(" title") or ref_clean.endswith(" sidenote")


def _mixed_heading_structural_insert_ref(ref: str, *, action: str) -> str:
    """Return the structural component of ``X and heading`` insert targets.

    UK effects sometimes report an inserted structural payload plus its heading
    carrier as one affected-provision string, e.g. ``s. 61(2A)(2B) and
    heading``.  The heading suffix is not a body target, but it also must not
    block the source-owned inserted children.
    """
    if action != "insert":
        return ""
    ref_clean = " ".join(str(ref or "").split()).strip()
    if not re.search(r"\s+and\s+heading\s*$", ref_clean, flags=re.I):
        return ""
    if "cross-heading" in ref_clean.lower() or "cross heading" in ref_clean.lower():
        return ""
    structural_ref = re.sub(r"\s+and\s+heading\s*$", "", ref_clean, flags=re.I).strip()
    if "(" not in structural_ref or ")" not in structural_ref:
        return ""
    return structural_ref


def _heading_facet_append_fragment(extracted_text: Optional[str]) -> Optional[dict[str, Any]]:
    for fragment in parse_fragment_substitution(extracted_text or ""):
        if str(fragment.get("original") or "") == "TEXT_FROM__TO_END":
            replacement = str(fragment.get("replacement") or "")
            if replacement:
                return fragment
    return None


def _heading_facet_after_anchor_insert_fragment(extracted_text: Optional[str]) -> Optional[dict[str, Any]]:
    """Return a bounded heading/title insertion after an explicit quoted anchor."""
    text = " ".join((extracted_text or "").split()).strip()
    if not text:
        return None
    match = re.search(
        r"\bafter\s+[“\"'‘](?P<anchor>.*?)[”\"'’],?\s+"
        r"(?:there\s+(?:is|are|shall\s+be)\s+inserted|insert)"
        r"(?:\s+(?:the\s+)?words?)?\s+[“\"'‘](?P<inserted>.*?)[”\"'’]",
        text,
        flags=re.I | re.S,
    )
    if match is None:
        return None
    anchor = match.group("anchor").strip()
    inserted = match.group("inserted").strip()
    if not anchor or not inserted:
        return None
    joiner = "" if anchor.endswith((" ", "\t", "\n", "\r")) or inserted.startswith((" ", ",", ".", ";", ":", ")")) else " "
    return {
        "original": anchor,
        "replacement": f"{anchor}{joiner}{inserted}",
        "rule_id": "uk_effect_heading_facet_after_anchor_insert_text_patch",
    }


def _heading_facet_full_replacement_fragment(extracted_text: Optional[str]) -> Optional[dict[str, Any]]:
    """Return an explicit full heading/title/sidenote replacement fragment."""
    text = " ".join((extracted_text or "").split()).strip()
    if not text:
        return None
    match = re.search(
        r"\b(?:the\s+)?(?:section\s+)?(?:heading|title|sidenote)"
        r"(?:\s+to\s+the\s+section)?\s+becomes\s+(?P<replacement>.+)$",
        text,
        flags=re.I | re.S,
    )
    if match is None:
        return None
    replacement = match.group("replacement").strip()
    replacement = replacement.strip(" “”\"'‘’")
    replacement = re.sub(r"^(?:\.\s*)+", "", replacement).strip(" “”\"'‘’")
    replacement = re.sub(r"(?:\s*\.)+$", "", replacement).strip(" “”\"'‘’")
    if not replacement:
        return None
    return {
        "original": "TEXT_ALL",
        "replacement": replacement,
        "rule_id": "uk_effect_heading_facet_full_replacement_text_patch",
    }


def _is_heading_facet_word_patch_supported(effect_type: str, extracted_text: Optional[str] = None) -> bool:
    """Return whether a UK heading-facet effect can carry an explicit text patch."""
    normalized = " ".join((effect_type or "").lower().split())
    if normalized in {"substituted", "replaced"}:
        return _heading_facet_full_replacement_fragment(extracted_text) is not None
    if normalized in {
        "words substituted",
        "word substituted",
        "words omitted",
        "word omitted",
        "words repealed",
        "word repealed",
    }:
        return True
    if normalized in {"words inserted", "word inserted"}:
        return (
            _heading_facet_append_fragment(extracted_text) is not None
            or _heading_facet_after_anchor_insert_fragment(extracted_text) is not None
        )
    return False


def _is_direct_section_paragraph_ref(ref: str) -> bool:
    ref_clean = " ".join(str(ref or "").strip().lower().split())
    return bool(re.search(r"\b(?:s|section)\.?\s+\d+[a-z]?\s*\(\s*[a-z]\s*\)", ref_clean))


def _is_crossheading_ref(ref: str) -> bool:
    ref_clean = str(ref or "").strip().lower()
    return "cross-heading" in ref_clean or "cross heading" in ref_clean or "crossheading" in ref_clean


def _is_schedule_note_ref(ref: str) -> bool:
    ref_clean = " ".join(str(ref or "").strip().lower().split())
    return bool(re.search(r"\bsch(?:edule)?\.?\s+[0-9a-z]+(?:\s+|\s+pt\.\s+[0-9a-z]+\s+)note(?:\s+\d+)?\b", ref_clean))


_CROSSHEADING_BEFORE_ANCHOR_REPLACEMENT_RULE = "uk_effect_crossheading_before_anchor_replacement_text_patch"
_CROSSHEADING_BEFORE_ANCHOR_TEXT_PATCH_RULE = "uk_effect_crossheading_before_anchor_text_patch"
_CROSSHEADING_AND_STRUCTURAL_REPLACEMENT_SPLIT_RULE = (
    "uk_effect_crossheading_and_structural_replacement_split_lowered"
)


def _crossheading_before_anchor_replacement_text(extracted_text: Optional[str]) -> Optional[str]:
    """Return explicit replacement text for ``heading before paragraph X`` cross-heading claims."""
    text = " ".join((extracted_text or "").split())
    if not text:
        return None
    match = re.search(
        r"\bfor\s+(?:the\s+)?(?:italic\s+)?(?:heading|cross-heading|cross heading)\s+"
        r"before\s+(?:paragraph|section|article)\s+[0-9A-Za-z().]+\s+"
        r"substitute\s*[—-]?\s+(.+?)\s*$",
        text,
        re.I,
    )
    if match is None:
        return None
    replacement = match.group(1).strip()
    replacement = re.sub(r"\s+\.$", "", replacement).strip()
    return replacement or None


def _crossheading_before_anchor_text_patch_fragment(extracted_text: Optional[str]) -> Optional[dict[str, str]]:
    """Return a quoted text patch for ``cross-heading before section X`` claims."""
    text = " ".join((extracted_text or "").split())
    if not text:
        return None
    if not re.search(
        r"\b(?:heading|cross-heading|cross heading)\s+before\s+(?:paragraph|section|article)\s+[0-9A-Za-z().]+",
        text,
        flags=re.I,
    ):
        return None
    fragments = parse_fragment_substitution(text)
    if len(fragments) != 1:
        return None
    fragment = dict(fragments[0])
    original = str(fragment.get("original") or "").strip()
    replacement = str(fragment.get("replacement") or "").strip()
    if not original or replacement == "":
        return None
    return {
        "original": original,
        "replacement": replacement,
        "rule_id": _CROSSHEADING_BEFORE_ANCHOR_TEXT_PATCH_RULE,
    }


def _structural_children(el: ET.Element) -> tuple[ET.Element, ...]:
    structural_tags = {
        "Part",
        "Chapter",
        "EUChapter",
        "Pblock",
        "P1group",
        "Section",
        "P1",
        "Article",
        "Rule",
        "Subsection",
        "P2",
        "P3",
        "P4",
        "Schedule",
    }
    return tuple(child for child in list(el) if _tag(child) in structural_tags)


def _crossheading_and_structural_replacement_heading_text(
    *,
    affected_ref: str,
    extracted_el: Optional[ET.Element],
    target: LegalAddress,
) -> Optional[str]:
    """Return title text for explicit ``paragraph X and cross-heading`` replacements."""
    if extracted_el is None or "cross-heading" not in affected_ref.lower():
        return None
    target_label = _clean_num(_addr_leaf_label(target) or "")
    if not target_label:
        return None

    for amendment in extracted_el.iter():
        if _tag(amendment) not in {"BlockAmendment", "InlineAmendment"}:
            continue
        for wrapper in amendment.iter():
            if _tag(wrapper) not in {"P1group", "Pblock"}:
                continue
            title_el = wrapper.find(f"./{{{_LEG_NS}}}Title")
            if title_el is None:
                continue
            heading_text = _text_content(title_el)
            if not heading_text:
                continue
            structural_children = _structural_children(wrapper)
            if not structural_children:
                continue
            first_child_label = _clean_num(_direct_structural_num(structural_children[0]))
            if first_child_label == target_label:
                return heading_text
    return None


def _clone_element(el: ET.Element) -> ET.Element:
    return ET.fromstring(ET.tostring(el, encoding="unicode"))


def _retarget_instruction_element_to_target(
    extracted_el: ET.Element,
    target: LegalAddress,
    extracted_text: Optional[str],
) -> Optional[ET.Element]:
    """Retarget instruction paragraphs like '27 Section 100 ...' to the real target.

    Some archive-backed affects extracts hand us the amending schedule paragraph
    itself (`P1`, `P2`, `P3`) rather than a nested replacement node. When the
    direct structural number on that element is the amending paragraph number,
    but the text explicitly introduces a different target provision, using the
    raw element as payload fabricates a subtree rooted at the amendment
    paragraph number. In those cases, clone the element and rewrite its direct
    number to the actual affected target label before parsing it as a payload.
    """
    target_kind = _addr_leaf_kind(target)
    target_label = _addr_leaf_label(target)
    if not target_kind or not target_label or not extracted_text:
        return None

    direct_num = _direct_structural_num(extracted_el)
    if not direct_num or _clean_num(direct_num) == _clean_num(target_label):
        return None

    text = " ".join(extracted_text.split())
    label_rx = re.escape(target_label)
    target_patterns = {
        "section": rf"\bsection\s+{label_rx}\b",
        "article": rf"\barticle\s+{label_rx}\b",
        "rule": rf"\brule\s+{label_rx}\b",
        "subsection": rf"\bsubsection\s*\({label_rx}\)\b",
        "paragraph": rf"\bparagraph\s*\({label_rx}\)\b",
        "subparagraph": rf"\bsub-?paragraph\s*\({label_rx}\)\b",
        "item": rf"\bitem\s*\({label_rx}\)\b",
    }
    pattern = target_patterns.get(target_kind)
    if pattern is None or not re.search(pattern, text, re.I):
        return None

    clone = _clone_element(extracted_el)
    num_el = clone.find(f"./{{{_LEG_NS}}}Pnumber")
    if num_el is None:
        num_el = clone.find(f"./{{{_LEG_NS}}}Number")
    if num_el is None:
        return None
    num_el.text = target_label
    for child in list(num_el):
        child.tail = ""
    return clone


